CREATE TABLE IF NOT EXISTS achievements ("user" VARCHAR(50), achievement VARCHAR(30), first_seen TIMESTAMP NOT NULL, last_seen TIMESTAMP NOT NULL, last_seen_iteration INT NOT NULL, CONSTRAINT pk_achievements PRIMARY KEY ("user", achievement), CONSTRAINT fk_achievements_user__name FOREIGN KEY ("user") REFERENCES users("name") ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_achievements_last_seen_iteration__id FOREIGN KEY (last_seen_iteration) REFERENCES request_iterations(id) ON DELETE RESTRICT ON UPDATE RESTRICT);